from anthropic import AsyncAnthropic, APIStatusError
import httpx

async def chat_with_retry_header(client: AsyncAnthropic, **kwargs) -> dict:
    for attempt in range(3):
        try:
            return await client.messages.create(**kwargs)
        except APIStatusError as e:
            if e.status_code != 429:
                raise
            # Anthropic surfaces Retry-After in the response headers
            retry_after_str = e.response.headers.get("retry-after", "")
            if retry_after_str.isdigit():
                wait = int(retry_after_str)
            else:
                # Fall back to exponential backoff if header absent
                wait = min(60.0, 1.0 * (2 ** attempt))
            await asyncio.sleep(wait)
    raise RuntimeError("Exhausted retries")


# OpenAI equivalent — same header, different exception class
from openai import AsyncOpenAI, RateLimitError

async def openai_chat_with_retry(client: AsyncOpenAI, **kwargs) -> dict:
    for attempt in range(3):
        try:
            return await client.chat.completions.create(**kwargs)
        except RateLimitError as e:
            # OpenAI RateLimitError has a .response attribute with headers
            headers = getattr(e.response, "headers", {})
            retry_after_str = headers.get("retry-after", "")
            wait = float(retry_after_str) if retry_after_str else min(60.0, 2 ** attempt)
            await asyncio.sleep(wait)
    raise RuntimeError("Exhausted retries")

from src.services.genai.interface import LLMClient, ChatMessage, ChatResult
from src.services.genai.errors import ProviderError, ProviderConnectionError
import logging

logger = logging.getLogger(__name__)

class ChatService:
    def __init__(
        self,
        primary: LLMClient,
        fallback: LLMClient | None = None,
        max_retries: int = 3,
    ) -> None:
        self._primary = primary
        self._fallback = fallback
        self._max_retries = max_retries

    async def chat(self, messages: list[ChatMessage], **kwargs) -> ChatResult:
        try:
            return await with_retry(
                lambda: self._primary.chat(messages, **kwargs),
                max_attempts=self._max_retries,
            )
        except (ProviderError, ProviderConnectionError) as primary_exc:
            if self._fallback is None:
                raise

            logger.warning(
                "primary provider failed after %d attempts, routing to fallback: %s",
                self._max_retries,
                primary_exc,
            )
            # Fallback also retried, but with fewer attempts
            return await with_retry(
                lambda: self._fallback.chat(messages, **kwargs),
                max_attempts=2,
            )
